import{z}from"zod";import{v4 as uuidv4}from"uuid";import{checkWebSocketServerForUIProTool,getWebSocketServerForUIProTool}from"./utils.js";export const TOOL_SCHEMA_GET_VARIABLES_AND_TOKENS=z.object({});export const TOOL_NAME_GET_VARIABLES_AND_TOKENS="getVariablesAndTokens";export const TOOL_DEFINITION_GET_VARIABLES_AND_TOKENS={name:"getVariablesAndTokens",description:"Fetch all local design variables, tokens and variable collections from the connected Figma file. Returns collections with their modes and variables with their types, scopes, and values.",inputSchema:{type:"object",properties:{},required:[]}};export async function runToolGetVariables(_args){try{const webSocketServer=getWebSocketServerForUIProTool(),serverCheckResult=checkWebSocketServerForUIProTool(webSocketServer);if(!serverCheckResult.valid)return serverCheckResult.data;const connectionManager=webSocketServer.getConnectionManager(),request={id:uuidv4(),type:"GET_VARIABLES_AND_TOKENS"},response=await connectionManager.sendRequest(request,3e4);if(!response.success||response.error)return{isError:!0,content:[{type:"text",text:`Error fetching variables: ${response.error||"Unknown error"}`}]};if(!response.data)return{isError:!0,content:[{type:"text",text:"No variable data received from Figma plugin"}]};const{collections:collections,variables:variables,textStyles:textStyles}=response.data,roundNumbersDeep=value=>{if("number"==typeof value&&Number.isFinite(value))return Math.round(100*value)/100;if(Array.isArray(value))return value.map((item=>roundNumbersDeep(item)));if(value&&"object"==typeof value){const output={};for(const[key,val]of Object.entries(value))output[key]=roundNumbersDeep(val);return output}return value},roundedResult=roundNumbersDeep({collections:collections,variables:variables,textStyles:textStyles});let text=JSON.stringify(roundedResult,null,1);return text=text.replace(/VARIABLE_ALIAS/g,"a"),{content:[{type:"text",text:`Successfully retrieved ${collections.length} collections, ${variables.length} variables and ${textStyles.length} textStyles from Figma.\ntype='a' means "VARIABLE_ALIAS"\n\n${text}`}]}}catch(error){return{isError:!0,content:[{type:"text",text:`Error fetching variables: ${error.message||error}`}]}}}